{
  "sentences": [
    {
      "text": "我每天早上六點起床。",
      "pinyin": "Wǒ měitiān zǎoshang liù diǎn qǐchuáng.",
      "pinyin_numeric": "wo3 mei3tian1 zao3shang4 liu4 dian3 qi3chuang2",
      "translation_en": "I get up at six every morning.",
      "translation_ko": "저는 매일 아침 여섯 시에 일어납니다."
    },
    {
      "text": "他每天中午吃午餐。",
      "pinyin": "Tā měitiān zhōngwǔ chī wǔcān.",
      "pinyin_numeric": "ta1 mei3tian1 zhong1wu3 chi1 wu3can1",
      "translation_en": "He eats lunch every noon.",
      "translation_ko": "그는 매일 점심에 점심을 먹습니다."
    },
    {
      "text": "我們每天晚上看電視。",
      "pinyin": "Wǒmen měitiān wǎnshang kàn diànshì.",
      "pinyin_numeric": "wo3men5 mei3tian1 wan3shang4 kan4 dian4shi4",
      "translation_en": "We watch TV every evening.",
      "translation_ko": "우리는 매일 저녁에 텔레비전을 봅니다."
    },
    {
      "text": "她每天下午去圖書館看書。",
      "pinyin": "Tā měitiān xiàwǔ qù túshūguǎn kàn shū.",
      "pinyin_numeric": "ta1 mei3tian1 xia4wu3 qu4 tu2shu1guan3 kan4 shu1",
      "translation_en": "She goes to the library to read books every afternoon.",
      "translation_ko": "그녀는 매일 오후에 도서관에 가서 책을 봅니다."
    },
    {
      "text": "我每天上班以前先喝一杯咖啡。",
      "pinyin": "Wǒ měitiān shàngbān yǐqián xiān hē yī bēi kāfēi.",
      "pinyin_numeric": "wo3 mei3tian1 shang4ban1 yi3qian2 xian1 he1 yi1 bei1 ka1fei1",
      "translation_en": "I drink a cup of coffee before going to work every day.",
      "translation_ko": "저는 매일 출근하기 전에 먼저 커피 한 잔을 마십니다."
    },
    {
      "text": "他每天下班以後去公園散步。",
      "pinyin": "Tā měitiān xiàbān yǐhòu qù gōngyuán sànbù.",
      "pinyin_numeric": "ta1 mei3tian1 xia4ban1 yi3hou4 qu4 gong1yuan2 san4bu4",
      "translation_en": "He goes for a walk in the park after getting off work every day.",
      "translation_ko": "그는 매일 퇴근 후에 공원에 가서 산책합니다."
    },
    {
      "text": "我們每天上課以前做功課。",
      "pinyin": "Wǒmen měitiān shàngkè yǐqián zuò gōngkè.",
      "pinyin_numeric": "wo3men5 mei3tian1 shang4ke4 yi3qian2 zuo4 gong1ke4",
      "translation_en": "We do homework before class every day.",
      "translation_ko": "우리는 매일 수업 전에 숙제를 합니다."
    },
    {
      "text": "她每天下課以後跟朋友一起走路回家。",
      "pinyin": "Tā měitiān xiàkè yǐhòu gēn péngyǒu yīqǐ zǒulù huí jiā.",
      "pinyin_numeric": "ta1 mei3tian1 xia4ke4 yi3hou4 gen1 peng2you3 yi1qi3 zou3lu4 hui2 jia1",
      "translation_en": "She walks home with friends after class every day.",
      "translation_ko": "그녀는 매일 수업 후에 친구와 함께 걸어서 집에 갑니다."
    },
    {
      "text": "我每天晚上睡覺以前聽音樂。",
      "pinyin": "Wǒ měitiān wǎnshang shuìjiào yǐqián tīng yīnyuè.",
      "pinyin_numeric": "wo3 mei3tian1 wan3shang4 shui4jiao4 yi3qian2 ting1 yin1yue4",
      "translation_en": "I listen to music before sleeping every night.",
      "translation_ko": "저는 매일 밤 자기 전에 음악을 듣습니다."
    },
    {
      "text": "他每天中午休息三十分鐘。",
      "pinyin": "Tā měitiān zhōngwǔ xiūxí sānshí fēnzhōng.",
      "pinyin_numeric": "ta1 mei3tian1 zhong1wu3 xiu1xi2 san1shi2 fen1zhong1",
      "translation_en": "He rests for thirty minutes every noon.",
      "translation_ko": "그는 매일 점심에 삼십 분 동안 휴식합니다."
    }
  ]
}
